import React, { useState } from 'react';
import ProductCard from '../components/ProductCard';

// TODO: Replace with API call — GET /api/products
const initialProducts = [
  { id: 1, name: 'Margherita Pizza', category: 'Pizza', price: 12.99 },
  { id: 2, name: 'Pepperoni Pizza', category: 'Pizza', price: 14.99 },
  { id: 3, name: 'Veggie Supreme', category: 'Pizza', price: 13.99 },
  { id: 4, name: 'Cola', category: 'Cold Drinks', price: 2.99 },
  { id: 5, name: 'Lemonade', category: 'Cold Drinks', price: 3.49 },
  { id: 6, name: 'Iced Tea', category: 'Cold Drinks', price: 2.49 },
  { id: 7, name: 'Garlic Bread', category: 'Breads', price: 4.99 },
  { id: 8, name: 'Cheese Breadsticks', category: 'Breads', price: 5.99 },
  { id: 9, name: 'Baguette', category: 'Breads', price: 3.99 },
];

function Menu() {
  const [filter, setFilter] = useState('All');
  const [products] = useState(initialProducts);

  const filteredProducts = filter === 'All' 
    ? products 
    : products.filter(p => p.category === filter);

  const handleAddToCart = (product) => {
    // Save to localStorage under key "cart"
    const existingCart = JSON.parse(localStorage.getItem('cart')) || [];
    existingCart.push(product);
    localStorage.setItem('cart', JSON.stringify(existingCart));
    alert('Added to cart!');
  };

  return (
    <div>
      <h2 className="text-center">Our Menu</h2>

      <div style={{ display: 'flex', justifyContent: 'center', gap: '10px', marginBottom: '20px' }}>
        {['All', 'Pizza', 'Cold Drinks', 'Breads'].map(category => (
          <button 
            key={category} 
            className="btn" 
            style={{ backgroundColor: filter === category ? '#1D3557' : '#E63946' }}
            onClick={() => setFilter(category)}
          >
            {category}
          </button>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' }}>
        {filteredProducts.map(product => (
           <ProductCard 
             key={product.id} 
             product={product} 
             onAddToCart={handleAddToCart} 
           />
        ))}
      </div>
    </div>
  );
}

export default Menu;
